class Solution(object):
    def canMakeSubsequence(self, str1, str2):
        i = j = 0
        n1, n2 = len(str1), len(str2)
        while i < n1 and j < n2:
            c1, c2 = str1[i], str2[j]
            # Match if equal or cyclic increment matches
            if c1 == c2 or chr((ord(c1) - ord('a') + 1) % 26 + ord('a')) == c2:
                j += 1
            i += 1
        return j == n2
